      { "group": "Customer Support", "impact": "Will use 'confirmed' in customer communications, creating false expectations of payment completion" },
      { "group": "Fulfillment / Warehouse", "impact": "Risk of premature fulfillment if systems react to 'confirmed' status without distinguishing quote vs order" },
      { "group": "Customers", "impact": "Confusion when 'confirmed' does not carry the same meaning across their quote and order experience" }
    ]
